from dataclasses import dataclass
from typing import Optional

@dataclass
class ModelLicenceRecord:
    model_name: str
    model_version: str
    licence_name: str
    osi_approved: bool
    commercial_use_permitted: bool
    mau_limit: Optional[int]           # None = no limit
    competing_service_restricted: bool
    output_use_policy: str             # brief description
    redistribution_permitted: bool
    source_url: str                    # link to actual licence text

    def is_safe_for_production(self, org_mau: int) -> bool:
        if not self.commercial_use_permitted:
            return False
        if self.mau_limit and org_mau > self.mau_limit:
            return False
        return True

    def risk_summary(self, org_mau: int) -> str:
        if not self.commercial_use_permitted:
            return f"BLOCKED — {self.model_name} does not permit commercial use."
        if self.mau_limit and org_mau > self.mau_limit:
            return (
                f"CAUTION — {self.model_name} community licence covers up to "
                f"{self.mau_limit:,} MAU; org has {org_mau:,}. "
                "Requires commercial licence agreement."
            )
        extra = " Note: competing service use restricted." if self.competing_service_restricted else ""
        return f"APPROVED — {self.model_name} ({self.licence_name}).{extra}"

from dataclasses import dataclass, field
from enum import Enum
from datetime import date
from typing import Optional

class ComponentType(str, Enum):
    LIBRARY     = "library"       # pip/npm/cargo dependency
    MODEL       = "model"         # neural network weights
    DATASET     = "dataset"       # training/fine-tuning data
    TOOL        = "tool"          # CLI tool packaged into image
    CONTAINER   = "container"     # base OS / runtime image

@dataclass
class SBOMComponent:
    name: str
    version: str                      # e.g. "4.41.2" or "commit-sha"
    component_type: ComponentType
    licence_spdx: str                 # SPDX identifier, e.g. "Apache-2.0"
    source_url: str                   # canonical download URL
    approval_tier: str                # PRE_APPROVED / LEGAL_REVIEW / PROHIBITED
    cve_checked_date: Optional[date] = None
    model_provider: Optional[str]    = None   # "huggingface" | "openai" | "anthropic"
    dataset_licence: Optional[str]   = None   # may differ from model licence

    def is_safe_to_ship(self) -> bool:
        """True only if approved and not holding a PROHIBITED licence."""
        return (
            self.approval_tier != "PROHIBITED"
            and self.licence_spdx not in {"GPL-2.0", "GPL-3.0", "AGPL-3.0", "SSPL-1.0"}
        )

    def needs_legal_sign_off(self) -> bool:
        return self.approval_tier == "LEGAL_REVIEW"

@dataclass
class SBOM:
    application_name: str
    version: str
    generated_date: date
    components: list[SBOMComponent] = field(default_factory=list)

    def blocked_components(self) -> list[SBOMComponent]:
        return [c for c in self.components if not c.is_safe_to_ship()]

    def pending_legal_review(self) -> list[SBOMComponent]:
        return [c for c in self.components if c.needs_legal_sign_off()]

    def is_shippable(self) -> bool:
        return len(self.blocked_components()) == 0

# Contribution pre-approval checklist (pseudo-code for governance tooling)
from dataclasses import dataclass
from enum import Enum
from typing import Optional

class ContributionRisk(str, Enum):
    LOW    = "low"      # pre-approved, self-service
    MEDIUM = "medium"   # manager approval required
    HIGH   = "high"     # legal + security review required

@dataclass
class ContributionRequest:
    contributor_email: str
    upstream_repo: str
    has_cla: bool
    contains_internal_algorithm: bool
    contains_internal_data: bool
    is_competitive_area: bool
    contribution_type: str   # "bugfix" | "feature" | "docs" | "infra"

    def risk_level(self) -> ContributionRisk:
        if self.contains_internal_algorithm or self.contains_internal_data:
            return ContributionRisk.HIGH
        if self.has_cla or self.is_competitive_area:
            return ContributionRisk.MEDIUM
        return ContributionRisk.LOW

    def approval_path(self) -> str:
        r = self.risk_level()
        if r == ContributionRisk.HIGH:
            return "Submit ticket to Legal + Security. SLA: 5 business days."
        if r == ContributionRisk.MEDIUM:
            return "Manager approval in governance portal. SLA: 2 business days."
        return "Self-service — log in OSS contribution tracker and proceed."
